function solve(s) {
    const N = s.length;

    // 1. Calculate prefix sums P. 
    // P[k] stores the sum of values up to index k-1. P has length N+1.
    // '1' maps to 1, '0' maps to -1.
    const P = new Array(N + 1).fill(0);
    for (let i = 0; i < N; i++) {
        const value = s[i] === '1' ? 1 : -1;
        P[i + 1] = P[i] + value;
    }

    let maxL = 0;

    // Map to store the first index k where a prefix sum S occurred.
    // Key: Sum S, Value: Index k
    const firstOccurrence = new Map();
    firstOccurrence.set(0, 0); // P[0] = 0

    // 2. Iterate through P to find the maximum length L = k - j 
    // such that P[k] - P[j] is 0, 2, or -2.
    for (let k = 1; k <= N; k++) {
        const currentSum = P[k];

        // Check for target difference D = 0, 2, -2

        // Case D = 0: P[k] = P[j]
        const target0 = currentSum;
        if (firstOccurrence.has(target0)) {
            const j = firstOccurrence.get(target0);
            maxL = Math.max(maxL, k - j);
        }

        // Case D = 2: P[k] - P[j] = 2  => P[j] = P[k] - 2
        const target2 = currentSum - 2;
        if (firstOccurrence.has(target2)) {
            const j = firstOccurrence.get(target2);
            maxL = Math.max(maxL, k - j);
        }

        // Case D = -2: P[k] - P[j] = -2 => P[j] = P[k] + 2
        const target_neg2 = currentSum + 2;
        if (firstOccurrence.has(target_neg2)) {
            const j = firstOccurrence.get(target_neg2);
            maxL = Math.max(maxL, k - j);
        }

        // Store the first occurrence of the current sum
        if (!firstOccurrence.has(currentSum)) {
            firstOccurrence.set(currentSum, k);
        }
    }

    return maxL;
}

